// History Screen Components Contract
// Files: src/screens/HistoryScreen.tsx, src/components/history/HistoryFilters.tsx,
//        src/components/history/EntryList.tsx, src/components/history/EntryCard.tsx

// Import from '@/screens'
export interface HistoryScreenProps {
  route?: {
    params?: {
      categoryId?: string;
      dateStart?: string;
      dateEnd?: string;
    };
  };
  navigation?: {
    navigate: (screen: string, params?: Record<string, unknown>) => void;
  };
}
export function HistoryScreen(props: HistoryScreenProps): React.ReactElement;

// Import from '@/components/history'
export interface HistoryFiltersProps {
  filters: TimeEntryFilters;
  onFiltersChange: (filters: TimeEntryFilters) => void;
  categories: Category[];
  disabled?: boolean;
}
export function HistoryFilters(props: HistoryFiltersProps): React.ReactElement;

export interface EntryListProps {
  entries: TimeEntry[];
  categories: Category[];
  hasNextPage?: boolean;
  isFetchingNextPage?: boolean;
  onFetchNextPage?: () => void;
  onRefresh?: () => void;
  isRefreshing?: boolean;
  isLoading?: boolean;
  onEntryPress?: (entry: TimeEntry) => void;
  onEntryEdit?: (entry: TimeEntry) => void;
  emptyMessage?: string;
}
export function EntryList(props: EntryListProps): React.ReactElement;

export interface EntryCardProps {
  entry: TimeEntry;
  categoryName: string | null;
  categoryColor: string | null;
  categoryType: string | null;
  onEdit?: (entry: TimeEntry) => void;
  onPress?: (entry: TimeEntry) => void;
}
export function EntryCard(props: EntryCardProps): React.ReactElement;

// Behavior notes:
// - HistoryScreen integrates useTimeEntries infinite query with filters
// - HistoryFilters has expandable panel with date range, category selector, notes search (300ms debounce), duration presets
// - EntryList uses FlatList with infinite scroll (onEndReachedThreshold=0.3), pull-to-refresh, section headers by date
// - EntryCard shows category color chip, type badge, date/time, duration, and truncated notes preview
// - Loading skeleton during initial fetch, empty state with customizable message
// - Navigation to EntryEdit modal on entry press/edit
